  7→
  8→const POST_TYPE_TEXT = 'text';
  9→const POST_TYPE_CANVAS = 'canvas';
 10→
 11→const simpleHash = (str) => {
 12→    let h = 0;
 13→    for(let i = 0; i < str.length; i++){
 14→        h = ((h << 5) - h + str.charCodeAt(i)) | 0;
 15→    }
 16→    return h;
 17→};
 18→
 19→const userHomeCoords = (userId) => {
 20→    const mid = Math.floor(userId.length / 2);
 21→    const xHash = Math.abs(simpleHash(userId.slice(0, mid)));
 22→    const yHash = Math.abs(simpleHash(userId.slice(mid)));
 23→    const x = (xHash % 50001) / 50000 * 50000 - 25000;
 24→    const y = (yHash % 50001) / 50000 * 50000 - 25000;
 25→    return {x, y};
 26→};
 27→
 28→const spiralLayout = (index) => {
 29→    if(index === 0) return {dx: 0, dy: 0};
 30→    const angle = index * 0.8;
 31→    const radius = 30 * Math.sqrt(index);
 32→    return {dx: radius * Math.cos(angle), dy: radius * Math.sin(angle)};
 33→};
 34→
 35→const normalizePostType = (postType) => {
 36→    if(typeof postType !== 'string'){
 37→        return POST_TYPE_TEXT;
 38→    }
 39→
 40→    const normalized = postType.trim().toLowerCase();
 41→    return normalized === POST_TYPE_CANVAS ? POST_TYPE_CANVAS : POST_TYPE_TEXT;
 42→}
 43→
 44→const parseCanvasDocInput = (canvasDoc) => {
 45→    if(!canvasDoc){
 46→        return null;
 47→    }
 48→
 49→    const parsedCanvasDoc = typeof canvasDoc === 'string' ? JSON.parse(canvasDoc) : canvasDoc;
 50→    if(!parsedCanvasDoc || typeof parsedCanvasDoc !== 'object'){
 51→        throw new Error('canvas_doc should be a valid object');
 52→    }
 53→
 54→    if(!Array.isArray(parsedCanvasDoc.snippets)){
 55→        throw new Error('canvas_doc.snippets should be an array');
 56→    }
 57→
 58→    return parsedCanvasDoc;
 59→}
 60→
 61→const extractCanvasPlainText = (canvasDoc) => {
 62→    if(!canvasDoc || !Array.isArray(canvasDoc.snippets)){
 63→        return '';
 64→    }
 65→
 66→    return canvasDoc.snippets
 67→        .map((snippet) => (typeof snippet?.text === 'string' ? snippet.text.trim() : ''))
 68→        .filter(Boolean)
 69→        .join(' ');
 70→}
 71→
 72→const parseTextContentSafely = (content) => {
 73→    if(typeof content !== 'string' || !content.trim()){
 74→        return null;
 75→    }
 76→
 77→    const parsedData = ParseContent(content);
 78→    if(!parsedData || typeof parsedData !== 'object'){
 79→        return null;
 80→    }
 81→
 82→    return parsedData;
 83→}
