499→export const updateRepostCaptionService = async(journalId, userId, caption) => {
500→    if(!journalId){
501→        throw {status: 400, error: 'journalId is undefined'};
502→    }
503→    if(!userId){
504→        throw {status: 400, error: 'userId is undefined'};
505→    }
506→
507→    const trimmedCaption = typeof caption === 'string' ? caption.trim() : '';
508→    if(trimmedCaption.length > 280){
509→        throw {status: 400, error: 'caption must be 280 characters or less'};
510→    }
511→
512→    const {data: journal, error: fetchError} = await supabase
513→        .from('journals')
514→        .select('id, user_id, is_repost')
515→        .eq('id', journalId)
516→        .eq('user_id', userId)
517→        .maybeSingle();
518→
519→    if(fetchError){
520→        console.error('failed to fetch journal for repost caption update:', fetchError.message);
521→        throw {status: 500, error: 'failed to fetch journal'};
522→    }
523→
524→    if(!journal){
525→        throw {status: 404, error: 'journal not found'};
526→    }
527→
528→    if(!journal.is_repost){
