 46→            if (event.key === "Escape") {
 47→                setSelectedMedia(null);
 48→            }
 49→        };
 50→
 51→        window.addEventListener("keydown", handleEscape);
 52→        return () => window.removeEventListener("keydown", handleEscape);
 53→    }, [selectedMedia]);
 54→
 55→    const profileParentContainer = typeof document !== "undefined" ? document.querySelector(".profile-parent-container") : null;
 56→
 57→    return (
 58→        <section className="profile-media-section" aria-label="Visited profile media">
