135→    const insertImageFromFile = (e) => {
136→        e.stopPropagation();
137→        if (inputRef.current) {
138→            inputRef.current.click();
139→        }
140→    };
141→
142→    const handleShowGradientPicker = (e) => {
143→        e.stopPropagation();
144→        setShowBgPicker(true);
145→    };
146→
147→    const handleHideGradientPicker = (e) => {
148→        e.stopPropagation();
149→        setShowBgPicker(false);
150→        setCroppedImage(userData?.background);
151→        setImageSrc(null);
152→        setGradientPicked(null);
153→    };
154→
155→    const handleSaveProfileEdit = async () => {
156→        setIsSavingProfile(true);
157→        const data = {
158→            name: profileEditName,
159→            image: profileEditAvatar,
160→            bio: profileEditBio,
161→            profileBg: croppedImage,
162→            dominantColors: dominantColors,
163→            secondaryColors: secondaryColors,
164→        };
165→
166→        try {
167→            const formdata = new FormData();
168→            Object.entries(data).forEach(([key, value]) => {
169→                if (value === undefined || value === null) {
170→                    return;
171→                }
172→                if (typeof value === "object" && value !== null && !(value instanceof File)) {
173→                    formdata.append(key, JSON.stringify(value));
174→                    return;
175→                }
176→
177→                formdata.append(key, value);
178→            });
179→
180→            await updateProfileData(formdata, session?.access_token);
181→        } catch {
182→            throw new Error("error saving update");
183→        } finally {
184→            setIsSavingProfile(false);
185→            setProfileEditAvatar(null);
186→            queryClient.invalidateQueries({ queryKey: ["userData"] });
